1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const quotePremium = (items: Item[]): number => {
17	  const basePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
18	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
19	  return Math.ceil(basePremium + firstInsurance + PROCESSING_FEE);
20	};
21	
22	export const runScenario = (input: unknown): unknown => {
23	  const scenario = input as Scenario;
24	  const results = scenario.steps.map(({ items }) => ({ premium: quotePremium(items) }));
25	  return { results };
26	};
