1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Simplest cases — quote with edge inputs
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Base premiums for main items
15	  it("single plain sword (newcomer, first contract) → 100 + 10 first-insurance + 5 fee = 115 G", () => {
16	    const result = runScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("single plain amulet (newcomer, first contract) → 60 + 6 first-insurance + 5 fee = 71 G (rounded up)", () => {
23	    const result = runScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("single plain staff (newcomer, first contract) → 80 + 8 first-insurance + 5 fee = 93 G", () => {
30	    const result = runScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff", material: "wood", enchantment: 2, cursed: false }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it("single plain potion (newcomer, first contract) → 40 + 4 first-insurance + 5 fee = 49 G", () => {
37	    const result = runScenario({
38	      customer: { yearsWithMHPCO: 0 },
39	      steps: [{ op: "quote", items: [{ type: "potion", material: "glass", enchantment: 1, cursed: false }] }],
40	    });
41	    expect(result).toEqual({ results: [{ premium: 49 }] });
42	  });
43	
44	  // Components — building-block discount
45	  it("2 runes → base premium 50 G (no block) → 60 G total (50 + 5 first-ins + 5 fee)", () => {
46	    const result = runScenario({
47	      customer: { yearsWithMHPCO: 0 },
48	      steps: [{ op: "quote", items: [{ type: "rune" }, { type: "rune" }] }],
49	    });
50	    expect(result).toEqual({ results: [{ premium: 60 }] });
51	  });
52	  it.todo("3 runes → base premium 60 G (block applies)");
53	  it.todo("4 runes → base premium 100 G (no block; block requires exactly 3)");
54	  it.todo("7 runes → base premium 175 G (no block; 7 = no group of exactly 3 with leftovers)");
55	
56	  // 'Alike' components — same type, not family
57	  it.todo("2 runes + 1 moonstone → base premium 75 G (no block, different types)");
58	  it.todo("3 runes + 3 moonstones → base premium 120 G (two separate blocks)");
59	
60	  // Modifier scope on multi-item policies
61	  it.todo("cursed sword + plain amulet → 100 + 60 + 50 (curse on sword only) = 210 G before further modifiers and fee");
62	
63	  // Modifier thresholds
64	  it.todo("customer with exactly 2 years → loyalty discount applies");
65	  it.todo("sword enchantment exactly 5 → high-enchantment surcharge applies");
66	  it.todo("cursed sword enchantment exactly 5 → both curse and high-enchantment surcharges apply");
67	  it.todo("sword enchantment 4, not cursed → no surcharge");
68	
69	  // Rounding in MHPCO's favor
70	  it.todo("premium 197.5 G → rounded up to 198 G");
71	
72	  // Integration examples
73	  it.todo("newcomer with cursed sword (steel, ench 3) → 165 G");
74	  it.todo("long-standing customer (3 years), 2nd contract, cursed sword ench 7 → 160 G");
75	
76	  // Quote errors
77	  it.todo("quote with unknown item type → CLI exits non-zero, writes error to stderr, no results");
78	
79	  // Claim — standard reimbursement
80	  it.todo("regular sword (steel, ench 3), damage 500 G → payout 400 G (500 − 100 deductible)");
81	  it.todo("damage to a rune (no enchantment/material), damage 200 G → payout 100 G (200 − 100)");
82	
83	  // Claim — enchantment threshold and dragon material
84	  it.todo("dragon sword, ench 8, damage 1000 G → payout 400 G (50% rule, then deductible)");
85	  it.todo("dragon sword, ench 9, damage 1000 G → payout 400 G (50% wins, then deductible)");
86	  it.todo("dragon sword, ench 5, damage 800 G → payout 700 G (dragon full, then deductible)");
87	  it.todo("steel sword, ench 9, damage 1000 G → payout 400 G (50% rule, then deductible)");
88	
89	  // Multiple items + deductible per damage event
90	  it.todo("dragon attack on insured sword (500 G) + amulet (300 G) → payout 600 G (deductible per damaged item)");
91	
92	  // Multiple items of the same type
93	  it.todo("policy covers two swords → insurance sum 2000, cap 4000; both damaged → each its own deductible");
94	  it.todo("damages contains more entries of a type than policy covers → CLI exits non-zero");
95	
96	  // Cap rules
97	  it.todo("policy with sword + amulet → insurance sum 1600, cap 3200");
98	  it.todo("policy with cursed sword (premium 165) → cap 2000 (based on unmodified insurance value)");
99	  it.todo("policy with sword + 3 runes (block) → insurance sum 1750 (block discount doesn't affect insurance sum)");
100	  it.todo("sword cap 2000; two successive claims of 1500 → 1st payout 1400 (cap rem 600), 2nd payout 600 (cap rem 0)");
101	
102	  // Rounding payout
103	  it.todo("payout 350.5 G → rounded down to 350 G (MHPCO's favor)");
104	
105	  // Claim errors
106	  it.todo("claim references damage entry whose item is not part of the policy → CLI exits non-zero with stderr");
107	  it.todo("claim damage with negative amount → CLI exits non-zero with stderr");
108	});
